1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - nextGeneration", () => {
6	  it("should kill a single live cell (underpopulation: 0 neighbors)", () => {
7	    expect(nextGeneration([[0, 0]])).toEqual([]);
8	  });
9	  it("should kill two adjacent live cells (underpopulation: 1 neighbor each)", () => {
10	    expect(
11	      nextGeneration([
12	        [0, 1],
13	        [1, 1],
14	      ]),
15	    ).toEqual([]);
16	  });
17	  it("should keep a live cell with 2 live neighbors alive (survival)", () => {
18	    const result = nextGeneration([
19	      [0, 0],
20	      [1, 1],
21	      [2, 2],
22	    ]);
23	    expect(result.sort()).toEqual([[1, 1]]);
24	  });
25	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
26	    // Ring pattern ###/.#./### — center cell (1,1) has 6 live neighbors
27	    const ring: Array<[number, number]> = [
28	      [0, 0],
29	      [1, 0],
30	      [2, 0],
31	      [1, 1],
32	      [0, 2],
33	      [1, 2],
34	      [2, 2],
35	    ];
36	    expect(nextGeneration(ring)).not.toContainEqual([1, 1]);
37	  });
38	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
39	    // ##./#.. → ##./##. — (1,1) is born; all three live cells survive
40	    const result = nextGeneration([
41	      [0, 0],
42	      [1, 0],
43	      [0, 1],
44	    ]);
45	    expect(result.sort()).toEqual(
46	      [
47	        [0, 0],
48	        [1, 0],
49	        [0, 1],
50	        [1, 1],
51	      ].sort(),
52	    );
53	  });
54	  it.todo("should keep a block still life unchanged");
55	  it.todo("should oscillate a vertical blinker to a horizontal blinker (negative coordinates)");
56	});
57

1	export type Cell = [number, number];
2	
3	const isNeighbor = ([x, y]: Cell, [nx, ny]: Cell): boolean =>
4	  Math.max(Math.abs(nx - x), Math.abs(ny - y)) === 1;
5	
6	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
7	  liveCells.filter((candidate) => isNeighbor(cell, candidate)).length;
8	
9	const survives = (liveNeighbors: number): boolean =>
10	  liveNeighbors === 2 || liveNeighbors === 3;
11	
12	const isBorn = (liveNeighbors: number): boolean => liveNeighbors === 3;
13	
14	const isLive = (cell: Cell, liveCells: Cell[]): boolean =>
15	  liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);
16	
17	const neighborsOf = ([x, y]: Cell): Cell[] => [
18	  [x - 1, y - 1],
19	  [x, y - 1],
20	  [x + 1, y - 1],
21	  [x - 1, y],
22	  [x + 1, y],
23	  [x - 1, y + 1],
24	  [x, y + 1],
25	  [x + 1, y + 1],
26	];
27	
28	const uniqueCells = (cells: Cell[]): Cell[] => [
29	  ...new Map(cells.map((cell) => [`${cell[0]},${cell[1]}`, cell])).values(),
30	];
31	
32	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
33	  const survivors = liveCells.filter((cell) =>
34	    survives(countLiveNeighbors(cell, liveCells)),
35	  );
36	  const births = uniqueCells(liveCells.flatMap(neighborsOf)).filter(
37	    (cell) =>
38	      !isLive(cell, liveCells) && isBorn(countLiveNeighbors(cell, liveCells)),
39	  );
40	  return [...survivors, ...births];
41	};
