it("should keep a block still life unchanged", () => {
  const block: Array<[number, number]> = [
    [0, 0],
    [1, 0],
    [0, 1],
    [1, 1],
  ];
  expect(nextGeneration(block).sort()).toEqual([...block].sort());
});
